class Solution:
    def preimageSizeFZF(self, k):
        def zeroes(x):
            c = 0
            p = 5
            while p <= x:
                c += x // p
                p *= 5
            return c
        # Independent approach: binary search the first x reaching >= k zeroes,
        # then count how many consecutive x hit exactly k (must be 0 or 5).
        lo, hi = 0, 5 * (k + 1) + 10
        while lo < hi:
            mid = (lo + hi) // 2
            if zeroes(mid) < k:
                lo = mid + 1
            else:
                hi = mid
        if zeroes(lo) != k:
            return 0
        count = 0
        x = lo
        while zeroes(x) == k:
            count += 1
            x += 1
        return count

