var preimageSizeFZF = function(k) {
    function zeroes(x) {
        let c = 0;
        let p = 5;
        while (p <= x) {
            c += Math.floor(x / p);
            p *= 5;
        }
        return c;
    }
    let lo = 0, hi = 5 * (k + 1);
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (zeroes(mid) < k) lo = mid + 1;
        else hi = mid;
    }
    return zeroes(lo) === k ? 5 : 0;
};
